# checkers.py

import pygame

# Constants
WHITE, BLACK = (255, 255, 255), (0, 0, 0)
RED, GREEN, BLUE = (255, 0, 0), (0, 255, 0), (0, 0, 255)
BOARD_SIZE = 8
CELL_SIZE = 60

# Board initialization
def init_board():
    board = []
    for row in range(BOARD_SIZE):
        board.append([])
        for col in range(BOARD_SIZE):
            if (row + col) % 2 == 1:
                if row < 3:
                    board[row].append('B')
                elif row > 4:
                    board[row].append('R')
                else:
                    board[row].append(None)
            else:
                board[row].append(None)
    return board

# Draw the board
def draw_board(screen, board):
    for row in range(BOARD_SIZE):
        for col in range(BOARD_SIZE):
            pygame.draw.rect(screen, WHITE, (col * CELL_SIZE, row * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
            if board[row][col] is not None:
                color = BLACK if board[row][col] == 'B' else RED
                pygame.draw.circle(screen, color, ((col + 0.5) * CELL_SIZE, (row + 0.5) * CELL_SIZE), CELL_SIZE // 2 - 5)

# Main game loop
def main():
    pygame.init()
    screen = pygame.display.set_mode((BOARD_SIZE * CELL_SIZE, BOARD_SIZE * CELL_SIZE))
    board = init_board()

    running = True
    selected = None

    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.MOUSEBUTTONDOWN:
                row, col = event.pos[1] // CELL_SIZE, event.pos[0] // CELL_SIZE
                if board[row][col] is not None and selected is None:
                    selected = (row, col)
                elif selected is not None:
                    new_row, new_col = row, col
                    # Add logic for move validation and piece movement
                    selected = None

        screen.fill((255, 255, 255))
        draw_board(screen, board)
        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
    main()
